class Solution {
    public long maxGCDScore(int[] nums, int k) {
        int n = nums.length;
        long maxScore = 0;

        for (int gcd = (int) 1e9; gcd >= 1; gcd--) {
            int[] count = new int[n];
            int left = 0, operations = 0;

            for (int right = 0; right < n; right++) {
                if (nums[right] % gcd == 0) count[right] = 1;
                else if (nums[right] * 2 % gcd == 0 && operations < k) {
                    count[right] = 1;
                    operations++;
                }

                while (operations == k) {
                    if (nums[left] % gcd == 0) count[left] = 0;
                    else if (nums[left] * 2 % gcd == 0) count[left] = 0;
                    left++;
                }

                if (right - left + 1 > 0) {
                    int windowCount = 0;
                    for (int i = left; i <= right; i++) windowCount += count[i];
                    if (windowCount == right - left + 1) {
                        maxScore = Math.max(maxScore, (long) gcd * (right - left + 1));
                    }
                }
            }
        }

        return maxScore;
    }
}
